describe('POST /products', () => {
  it('devrait créer un produit avec des données valides', async () => {
    const validProduct = { name: 'Smartphone', price: 599.99 };

    const response = await request(app.getHttpServer())
      .post('/products')
      .send(validProduct)
      .expect(201);

    expect(response.body).toHaveProperty('id');
    expect(response.body.name).toBe(validProduct.name);
    expect(response.body.price).toBe(validProduct.price);
  });

  it('devrait retourner 400 si le champ name est manquant', async () => {
    const invalidProduct = { price: 599.99 };

    const response = await request(app.getHttpServer())
      .post('/products')
      .send(invalidProduct)
      .expect(400);

    expect(response.body.message).toContain('name should not be empty');
  });

  it('devrait retourner 400 si le prix est négatif', async () => {
    const invalidProduct = { name: 'Smartphone', price: -10 };

    const response = await request(app.getHttpServer())
      .post('/products')
      .send(invalidProduct)
      .expect(400);

    expect(response.body.message).toContain('price must be a positive number');
  });
});
```

