describe('Order lifecycle e2e', () => {
  let createdOrderId: number;

  it('should create a new order', async () => {
    const newOrder = {
      customerName: 'Jean Dupont',
      email: 'jean@example.com',
      totalAmount: 299.99,
      items: [
        { productId: 1, quantity: 2, price: 149.99 }
      ]
    };

    const response = await request(app.getHttpServer())
      .post('/orders')
      .send(newOrder)
      .expect(201);

    expect(response.body).toHaveProperty('id');
    expect(response.body.status).toBe('pending');
    createdOrderId = response.body.id;
  });

  it('should retrieve the created order', async () => {
    const response = await request(app.getHttpServer())
      .get(`/orders/${createdOrderId}`)
      .expect(200);

    expect(response.body.customerName).toBe('Jean Dupont');
    expect(response.body.totalAmount).toBe(299.99);
  });

  it('should update order status to paid', async () => {
    const response = await request(app.getHttpServer())
      .patch(`/orders/${createdOrderId}`)
      .send({ status: 'paid' })
      .expect(200);

    expect(response.body.status).toBe('paid');
  });

  it('should list orders and find our order', async () => {
    const response = await request(app.getHttpServer())
      .get('/orders')
      .expect(200);

    const orderExists = response.body.some(o => o.id === createdOrderId);
    expect(orderExists).toBe(true);
  });

  it('should delete the order', async () => {
    await request(app.getHttpServer())
      .delete(`/orders/${createdOrderId}`)
      .expect(204);

    // Vérifier la suppression
    await request(app.getHttpServer())
      .get(`/orders/${createdOrderId}`)
      .expect(404);
  });
});
```

**Méthode 1 : Remplacer le provider dans le module de test**

```typescript
const mockStripeService = {
  createPaymentIntent: jest.fn().mockResolvedValue({ clientSecret: 'mock_secret' }),
  confirmPayment: jest.fn().mockResolvedValue({ status: 'succeeded' }),
};

beforeAll(async () => {
  const moduleFixture = await Test.createTestingModule({
    imports: [AppModule],
  })
    .overrideProvider(StripeService)
    .useValue(mockStripeService)
    .compile();
  // ...
});
```

**Méthode 2 : Utiliser des variables d'environnement**
```typescript
// Dans .env.test
STRIPE_API_KEY=sk_test_mock
STRIPE_WEBHOOK_SECRET=whsec_mock
```

**Méthode 3 : Intercepter les requêtes HTTP avec nock**
```typescript
import nock from 'nock';

beforeAll(() => {
  nock('https://api.stripe.com')
    .post('/v1/payment_intents')
    .reply(200, { id: 'pi_mock', client_secret: 'mock_secret' });
});
```

**Recommandation :** La méthode 1 (overrideProvider) est la plus propre pour NestJS car elle utilise l'IoC container et ne dépend pas du réseau.

